const SUPABASE_URL = 'https://faklxfakgzkpkbxfihzh.supabase.co';
const SUPABASE_API_KEY = 'REDACTED_SUPABASE_KEY';
const trigger = $('workflow_trigger').first().json;
const userId = trigger.user_id || '';

let recipient_email = trigger.recipient_email;
let bcc_email = trigger.bcc_email;
try {
  const rows = await this.helpers.httpRequest({
    method: 'GET',
    url: SUPABASE_URL + '/rest/v1/app_config_v2?key=in.(recipient_email,bcc_email)&select=key,value&user_id=eq.' + encodeURIComponent(userId),
    headers: { 'apikey': SUPABASE_API_KEY, 'Authorization': 'Bearer ' + SUPABASE_API_KEY }
  });
  for (const row of (rows || [])) {
    if (row.key === 'recipient_email' && !recipient_email) recipient_email = row.value;
    if (row.key === 'bcc_email' && !bcc_email) bcc_email = row.value;
  }
} catch (e) {}
if (!recipient_email) recipient_email = 'eric@agileadtesting.com';

return [{ json: { SUPABASE_URL, SUPABASE_API_KEY, recipient_email, bcc_email: bcc_email || '', userId } }];

const s = $('settings').first().json;
const trigger = $('workflow_trigger').first().json;
const supabaseUrl = s.SUPABASE_URL;
const apiKey = s.SUPABASE_API_KEY;
const userId = s.userId;
const headers = { 'apikey': apiKey, 'Authorization': 'Bearer ' + apiKey, 'Content-Type': 'application/json' };
const readHeaders = { 'apikey': apiKey, 'Authorization': 'Bearer ' + apiKey };
const userFilter = userId ? '&user_id=eq.' + encodeURIComponent(userId) : '';

const projectTitle = (trigger.project_title || '').replace(/^(from|of|for|in|the|a|an)\s+/i, '').replace(/^(from|of|for|in|the|a|an)\s+/i, '').trim();
const rawCh = (trigger.chapter_number || '').toString().trim();
const isProl = /^(prologue|prol|0)$/i.test(rawCh);
const isEpil = /^(epilogue|epil)$/i.test(rawCh);

// Find project
const projResp = await this.helpers.httpRequest({
  method: 'GET',
  url: supabaseUrl + '/rest/v1/writing_projects_v2?title=ilike.*' + encodeURIComponent(projectTitle) + '*&select=id,title,outline' + userFilter + '&limit=1',
  headers: readHeaders
});
if (!Array.isArray(projResp) || projResp.length === 0) {
  return [{ json: { error: true, result: 'Project not found: ' + projectTitle } }];
}
const project = projResp[0];
const outline = project.outline || {};
const characters = outline.characters || [];

// Determine chapter number
let chNum;
if (isProl) {
  chNum = 0;
} else if (isEpil) {
  chNum = 999;
} else {
  chNum = parseInt(rawCh);
}

// Detect prologue/epilogue by position
const allChapters = outline.chapters || [];
const chLabel = isProl ? 'Prologue' : (isEpil ? 'Epilogue' : 'Chapter ' + chNum);

// Fetch chapter from published_content_v2
let chapResp = await this.helpers.httpRequest({
  method: 'GET',
  url: supabaseUrl + '/rest/v1/published_content_v2?project_id=eq.' + project.id + '&chapter_number=eq.' + chNum + '&content_type=eq.chapter' + userFilter + '&limit=1',
  headers: readHeaders
});
if ((!Array.isArray(chapResp) || chapResp.length === 0) && isEpil && chNum !== 999) {
  chapResp = await this.helpers.httpRequest({
    method: 'GET',
    url: supabaseUrl + '/rest/v1/published_content_v2?project_id=eq.' + project.id + '&chapter_number=eq.999&content_type=eq.chapter' + userFilter + '&limit=1',
    headers: readHeaders
  });
  if (Array.isArray(chapResp) && chapResp.length > 0) chNum = 999;
}
if ((!Array.isArray(chapResp) || chapResp.length === 0) && isProl && chNum !== 0) {
  chapResp = await this.helpers.httpRequest({
    method: 'GET',
    url: supabaseUrl + '/rest/v1/published_content_v2?project_id=eq.' + project.id + '&chapter_number=eq.0&content_type=eq.chapter' + userFilter + '&limit=1',
    headers: readHeaders
  });
  if (Array.isArray(chapResp) && chapResp.length > 0) chNum = 0;
}
if (!Array.isArray(chapResp) || chapResp.length === 0) {
  return [{ json: { error: true, result: chLabel + ' not found in published content for "' + project.title + '". Has it been written yet?' } }];
}
const chapter = chapResp[0];

return [{ json: {
  chapter_text: chapter.content_text || '',
  chapter_title: chapter.title || '',
  chapter_id: chapter.id,
  project_id: project.id,
  project_title: project.title,
  outline: outline,
  characters: characters,
  chapterLabel: chLabel,
  chNum: chNum
} }];

const data = $input.first().json;
if (data.error) return [{ json: { ...data, has_issues: false, duplicate_count: 0, name_issue_count: 0, duplicates: [], name_issues: [], section_count: 0, chapter_text: '', characters: [], chapter_id: '', project_id: '', project_title: data.result || '', chapterLabel: '', chNum: 0, chapter_title: '' } }];

const chapterText = data.chapter_text;
const characters = data.characters || [];

// Split into sub-chapters by heading markers
const sections = chapterText.split(/\n(?=# )/);
const namedSections = sections.map((s, i) => {
  const titleMatch = s.match(/^#\s+(.+)/);
  return { title: titleMatch ? titleMatch[1].trim() : 'Section ' + (i + 1), body: s, index: i };
}).filter(s => s.body.trim().length > 100);

// N-gram duplicate detection
function getNgrams(text, n) {
  const words = text.toLowerCase().replace(/[^\w\s']/g, ' ').split(/\s+/).filter(w => w.length > 2);
  const grams = new Map();
  for (let i = 0; i <= words.length - n; i++) {
    const gram = words.slice(i, i + n).join(' ');
    if (!grams.has(gram)) grams.set(gram, []);
    grams.get(gram).push(i);
  }
  return { grams, words };
}

const NGRAM_SIZE = 5;
const MIN_RUN = 4; // minimum consecutive matching n-grams = 8-word phrase
const duplicates = [];

for (let i = 0; i < namedSections.length; i++) {
  const { grams: gramsA } = getNgrams(namedSections[i].body, NGRAM_SIZE);
  for (let j = i + 1; j < namedSections.length; j++) {
    const { grams: gramsB, words: wordsB } = getNgrams(namedSections[j].body, NGRAM_SIZE);
    // Find contiguous runs of shared n-grams in section j
    let run = [];
    let runStart = -1;
    for (let k = 0; k <= wordsB.length - NGRAM_SIZE; k++) {
      const gram = wordsB.slice(k, k + NGRAM_SIZE).join(' ');
      if (gramsA.has(gram)) {
        if (run.length === 0) runStart = k;
        run.push(gram);
      } else {
        if (run.length >= MIN_RUN) {
          const phraseLen = (run.length - 1) + NGRAM_SIZE;
          const phrase = wordsB.slice(runStart, runStart + phraseLen).join(' ');
          duplicates.push({
            text: phrase,
            word_count: phraseLen,
            section_a: namedSections[i].title,
            section_b: namedSections[j].title,
            location: 'First in "' + namedSections[i].title + '", repeated in "' + namedSections[j].title + '"'
          });
        }
        run = [];
      }
    }
    if (run.length >= MIN_RUN) {
      const phraseLen = (run.length - 1) + NGRAM_SIZE;
      const phrase = wordsB.slice(runStart, runStart + phraseLen).join(' ');
      duplicates.push({
        text: phrase,
        word_count: phraseLen,
        section_a: namedSections[i].title,
        section_b: namedSections[j].title,
        location: 'First in "' + namedSections[i].title + '", repeated in "' + namedSections[j].title + '"'
      });
    }
  }
}

// Character name inconsistency detection
const nameIssues = [];
const titlePrefixes = ['Professor', 'Prof', 'Dr', 'Mr', 'Mrs', 'Ms', 'Sir', 'Lady', 'Lord', 'Captain', 'General', 'Colonel', 'Inspector'];

for (const char of characters) {
  const nameParts = char.name.split(/\s+/);
  if (nameParts.length < 2) continue;
  const lastName = nameParts[nameParts.length - 1];

  // Find all "[Title/Name] LastName" patterns in the chapter
  const regex = new RegExp('\\b([A-Z][a-z]+(?:\\s+[A-Z][a-z]+)?)\\s+' + lastName + '\\b', 'g');
  let match;
  const foundForms = new Set();
  while ((match = regex.exec(chapterText)) !== null) {
    const fullMatch = match[0];
    if (fullMatch !== char.name && !foundForms.has(fullMatch)) {
      foundForms.add(fullMatch);
      // Check if this is a genuinely wrong form (not just first name or last name alone)
      const prefix = match[1];
      const isTitle = titlePrefixes.some(t => prefix.startsWith(t));
      const isPartOfCanonical = char.name.includes(prefix);
      // Skip if this form belongs to ANOTHER character with the same last name
      const honorifics = ['Miss', 'Mrs', 'Mr', 'Ms', 'Mister', 'Madam', 'Madame'];
      const isHonorific = honorifics.some(h => prefix === h);
      const sameSurnameChars = characters.filter(other => other.name !== char.name && other.name.endsWith(lastName));
      const belongsToOtherChar = sameSurnameChars.length > 0 && (isHonorific || sameSurnameChars.some(other => other.name === fullMatch || other.name.includes(prefix) || fullMatch.includes(other.name.split(' ')[0])));
      if (belongsToOtherChar) continue;
      if (!isPartOfCanonical || isTitle) {
        const count = (chapterText.match(new RegExp(fullMatch.replace(/[.*+?^${}()|[\]\\]/g, '\\$&'), 'g')) || []).length;
        nameIssues.push({
          found: fullMatch,
          expected: char.name,
          role: char.role,
          occurrences: count
        });
      }
    }
  }
}

return [{ json: {
  duplicates,
  name_issues: nameIssues,
  has_issues: duplicates.length > 0 || nameIssues.length > 0,
  duplicate_count: duplicates.length,
  name_issue_count: nameIssues.length,
  section_count: namedSections.length,
  chapter_text: data.chapter_text,
  characters: data.characters,
  chapter_id: data.chapter_id,
  project_id: data.project_id,
  project_title: data.project_title,
  chapterLabel: data.chapterLabel,
  chNum: data.chNum,
  chapter_title: data.chapter_title
} }];

const issues = $input.first().json;
const characters = issues.characters || [];

const charRef = characters.map(c =>
  '- ' + c.name + ' (' + c.role + ')' + (c.description ? ': ' + c.description : '')
).join('\n');

const dupList = issues.duplicates.map((d, i) =>
  (i + 1) + '. [' + d.word_count + ' words] ' + d.location + ':\n   "' + d.text.substring(0, 300) + (d.text.length > 300 ? '...' : '') + '"'
).join('\n\n');

const nameList = issues.name_issues.map((n, i) =>
  (i + 1) + '. Found: "' + n.found + '" (' + n.occurrences + ' times) -> Should be: "' + n.expected + '" (' + n.role + ')'
).join('\n');

// Only send ~2000 chars of context around each duplicate for Claude to see
let contextSnippets = '';
for (const d of issues.duplicates) {
  const idx = issues.chapter_text.toLowerCase().indexOf(d.text.substring(0, 40).toLowerCase());
  if (idx > -1) {
    const start = Math.max(0, idx - 200);
    const end = Math.min(issues.chapter_text.length, idx + d.text.length + 200);
    contextSnippets += '\n---DUPLICATE CONTEXT (in "' + d.section_b + '")---\n' + issues.chapter_text.substring(start, end) + '\n';
  }
}

const prompt = `You are a professional copy editor. Specific issues have been detected in a chapter. Return ONLY a JSON array of find/replace corrections.

## CANONICAL CHARACTER NAMES
${charRef}

## DETECTED DUPLICATE CONTENT (${issues.duplicate_count} passages)
${dupList || 'None detected.'}

For each duplicate: the passage appears in two sub-chapters. The LATER occurrence should be removed or replaced with a brief 1-2 sentence transition that maintains narrative flow. Do NOT keep the duplicated text.

## DETECTED NAME INCONSISTENCIES (${issues.name_issue_count} issues)
${nameList || 'None detected.'}

## CONTEXT AROUND DUPLICATES
${contextSnippets || 'None.'}

## INSTRUCTIONS
Return a JSON array of correction objects. Each object has:
- "find": the EXACT text to find in the chapter (copy it precisely, including punctuation)
- "replace": the replacement text (empty string "" to delete, or a brief transition sentence)
- "reason": brief explanation (e.g., "duplicate passage", "wrong character name")

For name corrections, include one entry per unique wrong form with the exact wrong text and the correct replacement.
For duplicate removals, include the exact paragraph(s) to remove from the LATER occurrence, with a brief transition if needed.

IMPORTANT: The "find" text must be an EXACT substring of the chapter. Copy it character-for-character. If you are unsure of the exact text, use a shorter unique phrase.

Return ONLY the JSON array. No commentary, no markdown fences.`;

return [{ json: { prompt } }];

const original = $('load_chapter_and_outline').first().json.chapter_text;
const llmOutput = ($input.first().json.text || $input.first().json.output || '').toString().trim();
const issues = $('detect_issues').first().json;
const chapterLabel = issues.chapterLabel;
const projectTitle = issues.project_title;

let corrections = [];
try {
  const jsonMatch = llmOutput.match(/\[[\s\S]*\]/);
  if (jsonMatch) corrections = JSON.parse(jsonMatch[0]);
} catch (e) {
  return [{ json: { error: true, result: 'Could not parse corrections: ' + e.message, corrected_text: original, diff_html: '<p>Error parsing corrections.</p>' } }];
}

function fuzzyFind(haystack, needle) {
  // 1. Exact match
  let idx = haystack.indexOf(needle);
  if (idx !== -1) return { start: idx, end: idx + needle.length, method: 'exact' };

  // 2. Case-insensitive
  idx = haystack.toLowerCase().indexOf(needle.toLowerCase());
  if (idx !== -1) return { start: idx, end: idx + needle.length, method: 'case-insensitive' };

  // 3. Word-level subsequence: find where most needle words appear in order
  const needleWords = needle.toLowerCase().replace(/[^a-z0-9\s']/g, '').split(/\s+/).filter(w => w.length > 2);
  if (needleWords.length < 3) return null;

  const hayLower = haystack.toLowerCase();
  let searchFrom = 0;

  while (searchFrom < hayLower.length) {
    const firstIdx = hayLower.indexOf(needleWords[0], searchFrom);
    if (firstIdx === -1) break;

    // Try to match subsequent words within a reasonable window
    let matched = 1;
    let lastMatchEnd = firstIdx + needleWords[0].length;
    const maxWindow = needle.length * 2;

    for (let w = 1; w < needleWords.length; w++) {
      const wIdx = hayLower.indexOf(needleWords[w], lastMatchEnd);
      if (wIdx !== -1 && wIdx - firstIdx < maxWindow) {
        matched++;
        lastMatchEnd = wIdx + needleWords[w].length;
      }
    }

    if (matched / needleWords.length >= 0.7) {
      return { start: firstIdx, end: lastMatchEnd, method: 'fuzzy (' + matched + '/' + needleWords.length + ' words)' };
    }

    searchFrom = firstIdx + 1;
  }
  return null;
}

let corrected = original;
const applied = [];
const failed = [];

for (const c of corrections) {
  if (!c.find || c.find.length < 5) continue;
  if (c.find === c.replace) continue;

  const match = fuzzyFind(corrected, c.find);
  if (match) {
    const actualFound = corrected.substring(match.start, match.end);
    const before = corrected.substring(0, match.start);
    const after = corrected.substring(match.end);
    corrected = before + (c.replace || '') + after;
    applied.push({ ...c, method: match.method, actualFound: actualFound.substring(0, 200) });
  } else {
    failed.push(c);
  }
}

corrected = corrected.replace(/\n{4,}/g, '\n\n\n');

const origWords = original.split(/\s+/).length;
const corrWords = corrected.split(/\s+/).length;
const wordDiff = corrWords - origWords;

let changesHtml = '';
for (const c of applied) {
  const isRemoval = !c.replace || c.replace.trim().length === 0;
  const findPreview = (c.actualFound || c.find).substring(0, 150).replace(/</g, '&lt;');
  const replacePreview = (c.replace || '').substring(0, 150).replace(/</g, '&lt;');
  changesHtml += '<tr><td style="padding:4px 8px;">' + (c.reason || 'correction') + '</td>' +
    '<td style="padding:4px 8px;background:#fdd;">' + findPreview + (findPreview.length >= 150 ? '...' : '') + '</td>' +
    '<td style="padding:4px 8px;' + (isRemoval ? '' : 'background:#dfd;') + '">' + 
    (isRemoval ? '<em>(removed)</em>' : replacePreview) + '</td>' +
    '<td style="padding:4px 8px;font-size:11px;color:#888;">' + (c.method || '') + '</td></tr>';
}
if (failed.length > 0) {
  for (const c of failed) {
    changesHtml += '<tr style="opacity:0.5;"><td style="padding:4px 8px;">NOT APPLIED</td>' +
      '<td style="padding:4px 8px;">' + c.find.substring(0, 100).replace(/</g, '&lt;') + '...</td>' +
      '<td style="padding:4px 8px;"><em>Text not found</em></td><td></td></tr>';
  }
}

const reportHtml = '<div style="border:2px solid #2196F3;border-radius:8px;padding:16px;margin-top:24px;font-family:sans-serif;">' +
  '<h2 style="color:#2196F3;margin-top:0;">Chapter Q/A Cleanup Report</h2>' +
  '<p><strong>Project:</strong> ' + projectTitle + ' | <strong>Chapter:</strong> ' + chapterLabel + '</p>' +
  '<h3>Summary</h3>' +
  '<p><strong>Duplicates found:</strong> ' + issues.duplicate_count + ' | <strong>Name issues:</strong> ' + issues.name_issue_count + '</p>' +
  '<p><strong>Corrections applied:</strong> ' + applied.length + ' | <strong>Failed:</strong> ' + failed.length + '</p>' +
  '<p><strong>Original:</strong> ' + origWords.toLocaleString() + ' words | <strong>Corrected:</strong> ' + corrWords.toLocaleString() + ' words (' + (wordDiff >= 0 ? '+' : '') + wordDiff + ')</p>' +
  '<h3>Changes Made</h3>' +
  '<table style="width:100%;border-collapse:collapse;margin:12px 0;">' +
  '<tr style="background:#f5f5f5;"><th style="text-align:left;padding:4px 8px;">Reason</th><th style="text-align:left;padding:4px 8px;">Original</th><th style="text-align:left;padding:4px 8px;">Replacement</th><th style="text-align:left;padding:4px 8px;">Match</th></tr>' +
  changesHtml + '</table></div>';

return [{ json: {
  corrected_text: corrected,
  diff_html: reportHtml,
  original_word_count: origWords,
  corrected_word_count: corrWords,
  corrections_applied: applied.length,
  corrections_failed: failed.length
} }];

const s = $('settings').first().json;
const supabaseUrl = s.SUPABASE_URL;
const apiKey = s.SUPABASE_API_KEY;
const userId = s.userId;
const headers = { 'apikey': apiKey, 'Authorization': 'Bearer ' + apiKey, 'Content-Type': 'application/json', 'Prefer': 'return=representation' };
const readHeaders = { 'apikey': apiKey, 'Authorization': 'Bearer ' + apiKey };

const diff = $input.first().json;
if (diff.error) return [{ json: diff }];

const chapterId = $('detect_issues').first().json.chapter_id;
const originalText = $('load_chapter_and_outline').first().json.chapter_text;
const correctedText = diff.corrected_text;

// Snapshot old version
try {
  const verResp = await this.helpers.httpRequest({
    method: 'GET',
    url: supabaseUrl + '/rest/v1/content_versions_v2?content_id=eq.' + chapterId + '&order=version_number.desc&limit=1&select=version_number',
    headers: readHeaders
  });
  const maxVer = (Array.isArray(verResp) && verResp.length > 0) ? verResp[0].version_number : 0;
  await this.helpers.httpRequest({
    method: 'POST',
    url: supabaseUrl + '/rest/v1/content_versions_v2',
    headers,
    body: {
      content_id: chapterId,
      version_number: maxVer + 1,
      content_text: originalText,
      changed_by: 'qa_chapter',
      change_note: 'Auto-snapshot before Q/A cleanup',
      user_id: userId
    }
  });
} catch (e) {
  // Version snapshot failed, continue anyway
}

// Save corrected text
await this.helpers.httpRequest({
  method: 'PATCH',
  url: supabaseUrl + '/rest/v1/published_content_v2?id=eq.' + chapterId + '&user_id=eq.' + encodeURIComponent(userId),
  headers,
  body: {
    content_text: correctedText,
    updated_at: new Date().toISOString()
  }
});

return [{ json: {
  saved: true,
  diff_html: diff.diff_html,
  corrected_text: correctedText,
  original_word_count: diff.original_word_count,
  corrected_word_count: diff.corrected_word_count
} }];

const data = $('load_chapter_and_outline').first().json;
const correctedText = $('snapshot_and_save').first().json.corrected_text;
const outline = data.outline || {};
const chNum = data.chNum;

let bookOutlineText = '';
if (outline) {
  const parts = [];
  if (outline.premise) parts.push('PREMISE: ' + outline.premise);
  if (outline.themes) parts.push('THEMES: ' + outline.themes.join(', '));
  if (outline.story_arc_name) parts.push('BOOK STORY ARC: ' + outline.story_arc_name);
  if (outline.characters) {
    parts.push('CHARACTERS:\n' + outline.characters.map(c => '- ' + c.name + ' (' + c.role + '): ' + c.arc).join('\n'));
  }
  if (outline.chapters) {
    parts.push('CHAPTER OUTLINE:\n' + outline.chapters.map(ch => 'Ch ' + ch.number + ' \u2014 ' + ch.title + ': ' + ch.brief + (ch.arc_notes ? ' [Arc: ' + ch.arc_notes + ']' : '')).join('\n'));
  }
  bookOutlineText = parts.join('\n\n');
}

let chapterOutlineText = 'No chapter outline found.';
let thisChapter = null;
if (outline.chapters) {
  thisChapter = outline.chapters.find(ch => ch.number === chNum);
}
if (thisChapter && thisChapter.chapter_outline && thisChapter.chapter_outline.sub_chapters) {
  const co = thisChapter.chapter_outline;
  chapterOutlineText = 'Chapter Story Arc: ' + (co.chapter_story_arc || 'Same as book') + '\n' +
    'Book Arc Beat: ' + (co.book_arc_beat || '') + '\n' +
    co.sub_chapters.map(sc => 'Sub-chapter ' + sc.number + ': ' + sc.title + '\n  Brief: ' + sc.brief + '\n  Characters: ' + (sc.characters || []).join(', ')).join('\n\n');
}

const bookArcName = outline.story_arc_name || '';
const chapterArcName = (thisChapter && thisChapter.chapter_outline) ? (thisChapter.chapter_outline.chapter_story_arc || bookArcName) : bookArcName;

const auditPrompt = `You are a story consistency auditor. A chapter has just been cleaned up. Verify it against the book outline, chapter outline, and story arc frameworks. Be thorough but fair.

## BOOK OUTLINE
${bookOutlineText}

## CHAPTER OUTLINE (SUB-CHAPTERS)
${chapterOutlineText}

## CHAPTER TEXT (CORRECTED)
${correctedText.substring(0, 150000)}

## VALIDATION CHECKLIST
For each item, respond PASS or FAIL with a brief explanation:

1. **Character Consistency**: Do all character names match the book outline exactly?
2. **Book Arc Advancement**: Does this chapter advance the book's story arc per the arc_notes?
3. **Chapter Outline Adherence**: Does the chapter follow the sub-chapter sequence? Look for title headings.
4. **Plot Consistency**: Does the chapter contradict established plot points?
5. **Theme Alignment**: Does the chapter support the book's stated themes?
6. **Story Drift Risk**: Any subtle changes that could take the narrative off path?
7. **Book Story Arc Compliance**: Does this chapter hit its assigned beat in ${bookArcName}?
8. **Chapter Story Arc Compliance**: Does the internal structure follow ${chapterArcName}?
9. **Arc Contradiction Check**: Does anything contradict the story arc's rules?

## OUTPUT FORMAT
Return JSON with:
- overall_status: "PASS" or "NEEDS_REVIEW"
- checks: array of {name, status ("PASS" or "FAIL"), detail}
- summary: one paragraph
- concerns: array of strings (empty if all PASS)`;

return [{ json: { auditPrompt } }];

const qaText = $input.first().json.text || $input.first().json.output || '';
const qaStr = typeof qaText === 'string' ? qaText : JSON.stringify(qaText);

let qaResult;
try {
  const jsonMatch = qaStr.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    qaResult = JSON.parse(jsonMatch[0]);
  } else {
    qaResult = { overall_status: 'UNKNOWN', summary: qaStr.substring(0, 500), checks: [], concerns: ['Could not parse response as JSON'] };
  }
} catch (e) {
  qaResult = { overall_status: 'UNKNOWN', summary: qaStr.substring(0, 500), checks: [], concerns: ['JSON parse error: ' + e.message] };
}

